INSERT INTO ebooks (id, title, author, r2_key, category_id, license_status, license_note) VALUES (1200, 'Episode 1: Ujian di Hari Sabtu', 'Tim Editorial ULYAH', 'ebooks/kisah-ashabus-sabt/id/kisah-ashabus-sabt-01-ujian-hari-sabtu.pdf', 5, 'original', 'Ditulis berdasarkan QS. Al-A''raf 163-163 (quran-json, CC-BY-4.0). Tidak ada kutipan pihak ketiga berhak cipta.');
INSERT INTO stories (title, slug, lang, series_key, episode_number, category_id, body, ai_generated, qc_status, source_format, status, confidence_score, related_ayah_id, pdf_ebook_id, published_at)
SELECT 'Episode 1: Ujian di Hari Sabtu', 'kisah-ashabus-sabt-01-ujian-hari-sabtu', 'id', 'kisah-ashabus-sabt', 1, 5, 'Allah menceritakan sebuah negeri di tepi laut dari kalangan Bani Israil yang diuji melalui perintah mengagungkan hari Sabtu (mereka dilarang bekerja dan menangkap ikan pada hari itu). Ujiannya sungguh berat: justru pada hari Sabtu itulah ikan-ikan datang berlimpah dan tampak jelas di permukaan air, sedangkan pada hari-hari lain ikan-ikan itu menghilang. Allah berfirman, "Dan tanyakanlah kepada mereka (Bani Israil) tentang negeri yang terletak di dekat laut ketika mereka melanggar aturan pada hari Sabtu, (yaitu) ketika datang kepada mereka ikan-ikan (yang berada di sekitar) mereka terapung-apung di permukaan air, padahal pada hari-hari yang bukan Sabtu ikan-ikan itu tidak datang kepada mereka. Demikianlah Kami menguji mereka disebabkan mereka berlaku fasik" (QS. Al-A''raf: 163).

Ujian ini menyingkap isi hati: apakah mereka lebih mengutamakan ketaatan kepada Allah, ataukah tergoda oleh keuntungan duniawi yang datang justru di saat yang dilarang. Sebagian dari mereka lalu mencari-cari celah (hilah) untuk melanggar aturan tanpa terang-terangan — misalnya memasang perangkap di hari Sabtu dan mengambil hasilnya keesokan harinya.

Hikmah: ujian sering datang justru lewat pintu yang paling menggoda. Ketaatan sejati diuji ketika larangan berbenturan dengan keinginan dan keuntungan. Mencari-cari celah untuk mengakali hukum Allah — meski tampak "halal secara teknis" — pada hakikatnya adalah bentuk pembangkangan.

Sumber & Catatan: dalil dari Al-Qur''an, QS. Al-A''raf: 163 (teks & terjemahan quran-json). Rincian cara mereka bersiasat (memasang jaring/kolam) yang beredar dalam sebagian tafsir berada di luar nas dan tidak dipastikan; yang pasti dari ayat adalah adanya pelanggaran hari Sabtu sebagai ujian.', 0, 'qc_pending', 'ai_original', 'published', 1.0,
  (SELECT id FROM ayah WHERE surah_id = 7 AND number = 163), 1200, datetime('now');
INSERT INTO ebooks (id, title, author, r2_key, category_id, license_status, license_note) VALUES (1201, 'Episode 1: The Test of the Sabbath', 'Tim Editorial ULYAH', 'ebooks/kisah-ashabus-sabt/en/kisah-ashabus-sabt-01-ujian-hari-sabtu.pdf', 5, 'original', 'Ditulis berdasarkan QS. Al-A''raf 163-163 (quran-json, CC-BY-4.0). Tidak ada kutipan pihak ketiga berhak cipta.');
INSERT INTO stories (title, slug, lang, series_key, episode_number, category_id, body, ai_generated, qc_status, source_format, status, confidence_score, related_ayah_id, pdf_ebook_id, published_at)
SELECT 'Episode 1: The Test of the Sabbath', 'kisah-ashabus-sabt-01-ujian-hari-sabtu', 'en', 'kisah-ashabus-sabt', 1, 5, 'Allah relates the story of a town by the sea, from among the Children of Israel, who were tested through the command to honour the Sabbath (they were forbidden to work or fish on that day). The test was severe: it was precisely on the Sabbath that the fish came in abundance, appearing plainly at the surface of the water, while on other days they would vanish. Allah said, "And ask them about the town that was by the sea — when they transgressed in [the matter of] the Sabbath — when their fish came to them openly on their Sabbath day, and the day they had no Sabbath they did not come to them. Thus did We give them trial because they were defiantly disobedient" (Qur''an 7:163).

This test exposed what was in the hearts: did they prioritise obedience to Allah, or were they lured by worldly gain that came precisely at the forbidden time? Some of them then sought loopholes (hilah) to break the rule without doing so openly — for instance setting traps on the Sabbath and collecting the catch the next day.

Reflection: a test often comes through the most tempting door. True obedience is tested when a prohibition collides with desire and profit. Seeking loopholes to outwit Allah''s law — even when it seems "technically permissible" — is in reality a form of defiance.

Source & Note: evidence from the Qur''an, 7:163 (text & translation from quran-json). Details of how they schemed (setting nets/pools) circulating in some tafsir are outside the text and not certain; what is certain from the verse is the violation of the Sabbath as a trial.', 0, 'qc_pending', 'ai_original', 'published', 1.0,
  (SELECT id FROM ayah WHERE surah_id = 7 AND number = 163), 1201, datetime('now');

INSERT INTO ebooks (id, title, author, r2_key, category_id, license_status, license_note) VALUES (1202, 'Episode 2: Tiga Golongan dan Mereka yang Melarang Kemungkaran', 'Tim Editorial ULYAH', 'ebooks/kisah-ashabus-sabt/id/kisah-ashabus-sabt-02-tiga-golongan.pdf', 5, 'original', 'Ditulis berdasarkan QS. Al-A''raf 164-165 (quran-json, CC-BY-4.0). Tidak ada kutipan pihak ketiga berhak cipta.');
INSERT INTO stories (title, slug, lang, series_key, episode_number, category_id, body, ai_generated, qc_status, source_format, status, confidence_score, related_ayah_id, pdf_ebook_id, published_at)
SELECT 'Episode 2: Tiga Golongan dan Mereka yang Melarang Kemungkaran', 'kisah-ashabus-sabt-02-tiga-golongan', 'id', 'kisah-ashabus-sabt', 2, 5, 'Menghadapi pelanggaran itu, penduduk negeri terbagi menjadi golongan-golongan. Ada yang melanggar, ada yang melarang kemungkaran, dan ada pula golongan ketiga yang tidak ikut melanggar tetapi mempertanyakan gunanya menasihati kaum yang sudah pasti dibinasakan. Allah berfirman, "Dan (ingatlah) ketika suatu umat di antara mereka berkata, ‘Mengapa kamu menasihati kaum yang akan dibinasakan atau diazab Allah dengan azab yang sangat keras?’ Mereka (yang memberi nasihat) menjawab, ‘Agar kami mempunyai alasan (lepas tanggung jawab) kepada Tuhanmu, dan agar mereka bertakwa’" (QS. Al-A''raf: 164).

Jawaban golongan yang melarang kemungkaran itu sungguh mulia: mereka menasihati bukan karena yakin nasihatnya pasti diterima, melainkan untuk menunaikan kewajiban di hadapan Allah dan berharap semoga masih ada yang kembali bertakwa. Ketika peringatan tak lagi diindahkan, datanglah keputusan Allah. Allah berfirman, "Maka setelah mereka melupakan apa yang diperingatkan kepada mereka, Kami selamatkan orang-orang yang melarang orang berbuat jahat dan Kami timpakan kepada orang-orang yang zalim siksaan yang keras, disebabkan mereka selalu berbuat fasik" (QS. Al-A''raf: 165).

Perhatikanlah: yang Allah sebut selamat secara tegas adalah "orang-orang yang melarang perbuatan jahat". Amar ma''ruf nahi munkar — mengajak kebaikan dan mencegah kemungkaran — menjadi sebab keselamatan mereka.

Hikmah: mencegah kemungkaran adalah kewajiban dan sekaligus perisai keselamatan, walau hasilnya belum tentu mengubah orang lain. Diam terhadap kemungkaran bukanlah sikap netral yang aman; yang selamat adalah mereka yang berani melarang keburukan dengan cara yang benar.

Sumber & Catatan: dalil dari Al-Qur''an, QS. Al-A''raf: 164-165. Adanya tiga golongan dipahami dari ayat (pelanggar, pelarang, dan yang berkata "mengapa menasihati"); yang Allah tegaskan selamat adalah golongan pelarang kemungkaran.', 0, 'qc_pending', 'ai_original', 'published', 1.0,
  (SELECT id FROM ayah WHERE surah_id = 7 AND number = 164), 1202, datetime('now');
INSERT INTO ebooks (id, title, author, r2_key, category_id, license_status, license_note) VALUES (1203, 'Episode 2: Three Groups, and Those Who Forbade the Evil', 'Tim Editorial ULYAH', 'ebooks/kisah-ashabus-sabt/en/kisah-ashabus-sabt-02-tiga-golongan.pdf', 5, 'original', 'Ditulis berdasarkan QS. Al-A''raf 164-165 (quran-json, CC-BY-4.0). Tidak ada kutipan pihak ketiga berhak cipta.');
INSERT INTO stories (title, slug, lang, series_key, episode_number, category_id, body, ai_generated, qc_status, source_format, status, confidence_score, related_ayah_id, pdf_ebook_id, published_at)
SELECT 'Episode 2: Three Groups, and Those Who Forbade the Evil', 'kisah-ashabus-sabt-02-tiga-golongan', 'en', 'kisah-ashabus-sabt', 2, 5, 'Facing that transgression, the townspeople split into groups. There were those who transgressed, those who forbade the evil, and a third group who did not join the transgression but questioned the point of advising a people already destined for destruction. Allah said, "And when a community among them said, ‘Why do you advise a people whom Allah is about to destroy or to punish with a severe punishment?’ they [the advisors] said, ‘To be absolved before your Lord, and so perhaps they may fear Him’" (Qur''an 7:164).

The answer of those who forbade the evil was truly noble: they advised not because they were sure the advice would be accepted, but to fulfil their duty before Allah and in hope that some might yet return to piety. When the warning was no longer heeded, Allah''s decision came. Allah said, "So when they forgot that by which they had been reminded, We saved those who had forbidden evil and seized those who wronged, with a wretched punishment, because they were defiantly disobeying" (Qur''an 7:165).

Note carefully: those Allah explicitly names as saved are "those who had forbidden evil." Enjoining good and forbidding wrong (amr bi''l-ma''ruf, nahy ''an al-munkar) was the cause of their salvation.

Reflection: forbidding wrong is both a duty and a shield of safety, even when it may not change others. Silence toward evil is not a safe neutrality; those saved are the ones who dared to forbid wrong in the right way.

Source & Note: evidence from the Qur''an, 7:164-165. The three groups are understood from the verses (the transgressors, the forbidders, and those who said "why advise"); those Allah affirms as saved are the forbidders of wrong.', 0, 'qc_pending', 'ai_original', 'published', 1.0,
  (SELECT id FROM ayah WHERE surah_id = 7 AND number = 164), 1203, datetime('now');

INSERT INTO ebooks (id, title, author, r2_key, category_id, license_status, license_note) VALUES (1204, 'Episode 3: ''Jadilah Kamu Kera yang Hina''', 'Tim Editorial ULYAH', 'ebooks/kisah-ashabus-sabt/id/kisah-ashabus-sabt-03-jadilah-kera-yang-hina.pdf', 5, 'original', 'Ditulis berdasarkan QS. Al-A''raf 166-166 (quran-json, CC-BY-4.0). Tidak ada kutipan pihak ketiga berhak cipta.');
INSERT INTO stories (title, slug, lang, series_key, episode_number, category_id, body, ai_generated, qc_status, source_format, status, confidence_score, related_ayah_id, pdf_ebook_id, published_at)
SELECT 'Episode 3: ''Jadilah Kamu Kera yang Hina''', 'kisah-ashabus-sabt-03-jadilah-kera-yang-hina', 'id', 'kisah-ashabus-sabt', 3, 5, 'Setelah peringatan diabaikan dan mereka justru semakin sombong terhadap larangan Allah, datanglah hukuman yang menghinakan atas orang-orang yang melampaui batas itu. Allah berfirman, "Maka setelah mereka bersikap sombong terhadap apa yang dilarang, Kami katakan kepada mereka, ‘Jadilah kamu kera yang hina’" (QS. Al-A''raf: 166).

Peristiwa ini juga ditegaskan dalam ayat lain, "Dan sungguh, kamu telah mengetahui orang-orang yang melakukan pelanggaran di antara kamu pada hari Sabtu, lalu Kami katakan kepada mereka, ‘Jadilah kamu kera yang hina’" (QS. Al-Baqarah: 65). Allah lalu menjadikan peristiwa itu sebagai peringatan bagi orang-orang pada masa itu dan pelajaran bagi orang-orang yang bertakwa sesudahnya (lihat QS. Al-Baqarah: 66).

Hikmah: dosa yang dilakukan dengan siasat dan kesombongan, sambil menutup telinga dari nasihat, mengundang murka Allah. Kehinaan yang menimpa mereka adalah balasan setimpal karena mereka merendahkan perintah Allah demi keuntungan sesaat. Sebaliknya, keselamatan diraih oleh mereka yang taat dan yang berani menegakkan nahi munkar.

Sumber & Catatan: dalil dari Al-Qur''an, QS. Al-A''raf: 166 dan QS. Al-Baqarah: 65-66. Ucapan "jadilah kamu kera yang hina" adalah nas Al-Qur''an. Para ulama berbeda pendapat mengenai hakikat perubahan itu (fisik atau maknawi); yang pasti dan wajib diimani adalah teks ayat sebagaimana adanya, tanpa memastikan rincian yang tidak disebut.', 0, 'qc_pending', 'ai_original', 'published', 1.0,
  (SELECT id FROM ayah WHERE surah_id = 7 AND number = 166), 1204, datetime('now');
INSERT INTO ebooks (id, title, author, r2_key, category_id, license_status, license_note) VALUES (1205, 'Episode 3: ''Be Apes, Despised''', 'Tim Editorial ULYAH', 'ebooks/kisah-ashabus-sabt/en/kisah-ashabus-sabt-03-jadilah-kera-yang-hina.pdf', 5, 'original', 'Ditulis berdasarkan QS. Al-A''raf 166-166 (quran-json, CC-BY-4.0). Tidak ada kutipan pihak ketiga berhak cipta.');
INSERT INTO stories (title, slug, lang, series_key, episode_number, category_id, body, ai_generated, qc_status, source_format, status, confidence_score, related_ayah_id, pdf_ebook_id, published_at)
SELECT 'Episode 3: ''Be Apes, Despised''', 'kisah-ashabus-sabt-03-jadilah-kera-yang-hina', 'en', 'kisah-ashabus-sabt', 3, 5, 'After the warning was ignored and they grew only more arrogant toward Allah''s prohibition, a humiliating punishment came upon those who transgressed. Allah said, "So when they were insolent about that which they had been forbidden, We said to them, ‘Be apes, despised’" (Qur''an 7:166).

This event is also affirmed in another verse: "And you had already known about those who transgressed among you concerning the Sabbath, so We said to them, ‘Be apes, despised’" (Qur''an 2:65). Allah then made that event a deterrent for the people of that time and a lesson for the God-fearing who came after (see Qur''an 2:66).

Reflection: a sin committed with scheming and arrogance, while closing one''s ears to counsel, invites Allah''s wrath. The humiliation that befell them was a fitting requital for belittling Allah''s command for a fleeting gain. Conversely, salvation was attained by those who obeyed and who dared to uphold the forbidding of wrong.

Source & Note: evidence from the Qur''an, 7:166 and 2:65-66. The words "Be apes, despised" are the Qur''an''s own text. Scholars differ over the nature of that transformation (physical or figurative); what is certain and to be believed is the text of the verse as it is, without asserting details it does not mention.', 0, 'qc_pending', 'ai_original', 'published', 1.0,
  (SELECT id FROM ayah WHERE surah_id = 7 AND number = 166), 1205, datetime('now');

